{
  "version": "3.0",
  "hooks": {
    "PreToolUse": {
      "security-scan-pre": {
        "condition": "tool === 'Bash' && command.includes('npm publish')",
        "action": "validate-secrets",
        "fail-on-error": true,
        "description": "Scan for secrets before publishing to npm"
      },
      "validate-model-selection": {
        "condition": "tool === 'Agent'",
        "action": "route-by-complexity",
        "routing": {
          "low": "haiku",
          "medium": "sonnet",
          "high": "opus"
        },
        "description": "Auto-select model based on task complexity"
      }
    },
    "PostToolUse": {
      "auto-lint-after-write": {
        "condition": "tool === 'Write' && filename.endsWith(('.js', '.ts', '.py'))",
        "action": "bash",
        "command": "npm run lint -- --fix {filename}",
        "timeout": 30000,
        "async": true,
        "description": "Auto-format code after writing"
      },
      "security-review-post": {
        "condition": "tool === 'Edit'",
        "action": "spawn-agent",
        "agent": "security-auditor",
        "files-to-review": "changed-files",
        "timeout": 120000,
        "description": "Auto-trigger security review after code edits"
      },
      "test-coverage-check": {
        "condition": "tool === 'Write' && filename.endsWith('.test.(js|ts|py)')",
        "action": "bash",
        "command": "npm test -- --coverage --silent && echo '✓ Coverage OK'",
        "timeout": 60000,
        "fail-on-coverage-drop": true,
        "description": "Verify test coverage doesn't drop"
      },
      "memory-store-commit": {
        "condition": "tool === 'Bash' && command.includes('git commit')",
        "action": "store-memory",
        "memory": {
          "key": "commit-{hash}",
          "value": "{commit-message}",
          "namespace": "commits",
          "ttl": 2592000,
          "tags": ["git", "tracking"]
        },
        "async": true,
        "description": "Auto-index commits to memory system"
      },
      "memory-sync-agents": {
        "condition": "agent-task-completed",
        "action": "sync-memory",
        "target": "all-agents",
        "namespace": "coordination",
        "async": true,
        "description": "Sync memory across agents after task completion"
      },
      "checkpoint-after-major-changes": {
        "condition": "files-changed > 5 OR lines-changed > 500",
        "action": "create-checkpoint",
        "compress": true,
        "async": true,
        "description": "Create checkpoint after major changes"
      }
    },
    "Stop": {
      "final-security-scan": {
        "action": "bash",
        "command": "claude-flow security scan --summary",
        "fail-on-error": true,
        "description": "Final security check before session end"
      },
      "memory-final-sync": {
        "action": "memory-sync",
        "namespace": "coordination",
        "compress": true,
        "description": "Final memory sync and compression"
      },
      "hive-mind-checkpoint": {
        "action": "bash",
        "command": "claude-flow hive-mind checkpoint --compress",
        "async": false,
        "description": "Save hive-mind state on session end"
      }
    }
  },
  "workers": {
    "auto-linter": {
      "command": "npm run lint -- --fix",
      "interval": 300000,
      "enabled": true
    },
    "security-scanner": {
      "command": "claude-flow security scan",
      "interval": 600000,
      "enabled": true
    },
    "memory-optimizer": {
      "command": "claude-flow memory gc --compress",
      "interval": 1800000,
      "enabled": true
    },
    "hive-health-check": {
      "command": "claude-flow hive-mind status --metrics",
      "interval": 300000,
      "enabled": true,
      "fail-on-agent-down": true
    }
  },
  "error-handling": {
    "on-hook-failure": "log-and-continue",
    "on-security-failure": "block-and-alert",
    "on-memory-failure": "log-only",
    "retry-policy": {
      "max-retries": 3,
      "backoff-ms": 1000
    }
  },
  "performance": {
    "max-hook-timeout": 300000,
    "async-by-default": false,
    "parallel-hooks": true,
    "hook-context-limit": "20MB"
  }
}

{
  "version": "3.0",
  "claude-code": {
    "model-default": "sonnet",
    "model-override-opus": true,
    "model-override-haiku": true,
    "extended-thinking": {
      "enabled": true,
      "budget-tokens": 20000
    },
    "fast-mode": false
  },
  "ruflo": {
    "daemon": {
      "enabled": true,
      "log-level": "info",
      "port": 9999,
      "heartbeat-interval": 300
    },
    "hive-mind": {
      "enabled": true,
      "consensus": "raft",
      "topology": "hierarchical",
      "max-agents": 8,
      "heartbeat-ms": 300,
      "election-timeout-ms": 3000,
      "self-healing": true,
      "rebalance-interval": 30000
    },
    "memory": {
      "backend": "hnsw",
      "dimension": 1536,
      "ef-construction": 200,
      "ef-search": 100,
      "compression": "enabled",
      "cleanup-interval": 1800000,
      "ttl-default": 2592000
    },
    "agents": {
      "auto-register": true,
      "config-path": ".claude/agents/",
      "shared-namespace": "coordination",
      "max-concurrent": 8
    }
  },
  "hooks": {
    "enabled": true,
    "config-file": ".claude/hooks.json",
    "error-on-failure": false,
    "log-all": true
  },
  "security": {
    "secret-detection": {
      "enabled": true,
      "patterns": ["API_KEY", "SECRET", "PASSWORD", "TOKEN"],
      "scan-frequency": "pre-commit"
    },
    "audit-log": {
      "enabled": true,
      "retention-days": 90,
      "path": ".claude/audit.log"
    }
  },
  "performance": {
    "context-limit": "50%",
    "compression": "enabled",
    "request-timeout": 60000,
    "cache-size-mb": 512
  },
  "openrouter": {
    "enabled": true,
    "fallback-models": {
      "haiku-fallback": "mistral-7b",
      "sonnet-fallback": "mixtral-8x7b",
      "opus-fallback": "claude-opus-online"
    }
  },
  "commands": {
    "attribution": false,
    "git-auto-sign": false
  }
}

